+fn cmd_corpus_verify(argv: &[String]) -> i32 {
+    let mut checksums_path = PathBuf::from(DEFAULT_CHECKSUMS_PATH);
+    let mut golden_dir = PathBuf::from(DEFAULT_GOLDEN_DIR);
+
